#include <stdio.h>

void loveLinear(int n) {
    for (int i = 1; i <= n; ++i) {
        printf("%d\n", i);       // O(n)
    }
}

void loveLog(int n) {
    for (int i = 1; i <= n; i *= 2) {
        printf("%d\n", i);       // O(log n)
    }
}

int locateN(const int a[], int n) {
    for (int i = 0; i < n; ++i) {
        if (a[i] == n) {
            return i;            // 最好 O(1)，最坏 O(n)
        }
    }
    return -1;
}
